import React from 'react';
import { Link } from 'react-router-dom';
import TopicsManager from './TopicsManager';
import './Sidebar.css';

function Sidebar({ blogs, loading, topics, onTopicsChange }) {
  return (
    <aside className="sidebar">
      <div className="sidebar-bottom">
        <div className="sidebar-topic-label">Topics</div>
        <div className="sidebar-topics">
          {topics.length === 0 ? (
            <div className="sidebar-empty">No topics yet</div>
          ) : (
            topics.map(topic => (
              <div key={topic.id || topic.name || topic} className="sidebar-topic">
                {topic.name || topic}
              </div>
            ))
          )}
        </div>
        <TopicsManager topics={topics} onTopicsChange={onTopicsChange} />
      </div>
    </aside>
  );
}

export default Sidebar;
